noncompliant:
// Noncompliant: Ternary operator with omitted second operand
int getValue(int x) {
    return x > 0 ? : -1;  // GNU extension
}

// Noncompliant: Case ranges in switch statements
void processValue(int value) {
    switch (value) {
        case 1 ... 5:  // GNU extension: case range
            printf("Low value\n");
            break;
        case 6 ... 10:
            printf("High value\n");
            break;
    }
}

// Noncompliant: Array initializer without =
struct Point {
    int x, y;
};
struct Point p[] = {
    [0] { 1, 2 },  // GNU extension: no = after [0]
    [1] { 3, 4 }
};

compliant:
// Compliant: Standard ternary operator
int getValue(int x) {
    return x > 0 ? x : -1;  // Standard C++
}

// Compliant: Standard switch statement
void processValue(int value) {
    if (value >= 1 && value <= 5) {
        printf("Low value\n");
    } else if (value >= 6 && value <= 10) {
        printf("High value\n");
    }
}

// Compliant: Standard array initialization
struct Point {
    int x, y;
};
struct Point p[] = {
    {1, 2},  // Standard C++ initialization
    {3, 4}
};
